use aiken/collection/list
use aiken/fuzz
use cardano/assets.{lovelace_of}
use cardano/transaction.{Output, OutputReference, Transaction}
pub type CdpDatum {
  owner:             ByteArray,
  collateral:        Int,
  debt:              Int,
  liquidation_ratio: Int,
  bonus_percent:     Int,
}

pub type CdpRedeemer {
  Repay
  Liquidate
}

fn is_undercollateralized(collateral: Int, debt: Int, ratio: Int) -> Bool {
  debt > 0 && collateral * 100 < debt * ratio
}

/// Liquidator pays discounted debt: debt * (100 - bonus_percent) / 100
fn discounted_debt(debt: Int, bonus_percent: Int) -> Int {
  debt * (100 - bonus_percent) / 100
}

fn liquidator_pays_discounted(
  outputs:       List<Output>,
  owner_addr:    Output,
  debt:          Int,
  bonus_percent: Int,
) -> Bool {
  let required = discounted_debt(debt, bonus_percent)
  let paid =
    list.foldl(
      outputs,
      0,
      fn(o, acc) {
        if o.address == owner_addr.address {
          acc + lovelace_of(o.value)
        } else {
          acc
        }
      },
    )
  paid >= required
}

validator cdp_liquidation_bonus {
  spend(
    datum: Option<CdpDatum>,
    redeemer: CdpRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Repay -> list.has(self.extra_signatories, d.owner)
      Liquidate ->
        is_undercollateralized(d.collateral, d.debt, d.liquidation_ratio)
    }
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_discounted_debt_zero_bonus(debt via fuzz.int_at_least(1)) {
  discounted_debt(debt, 0) == debt
}

test prop_discounted_debt_less_than_full(
  vals via fuzz.both(fuzz.int_at_least(100), fuzz.int_between(1, 50)),
) {
  let (debt, bonus) = vals
  discounted_debt(debt, bonus) < debt
}

test prop_discounted_debt_non_negative(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_between(0, 99)),
) {
  let (debt, bonus) = vals
  discounted_debt(debt, bonus) >= 0
}

test prop_undercollateralized_below_ratio(debt via fuzz.int_at_least(1)) {
  is_undercollateralized(debt * 119, debt * 100, 120)
}

// ── Negative / fail tests ────────────────────────────────────────────────────

// A position with zero debt can never be undercollateralized
test prop_zero_debt_never_undercollateralized(
  vals via fuzz.both(fuzz.int_at_least(0), fuzz.int_between(1, 500)),
) fail {
  let (collateral, ratio) = vals
  expect is_undercollateralized(collateral, 0, ratio)
}

// A well-collateralized position (collateral * 100 >= debt * ratio) must not
// be flagged as undercollateralized.
// collateral = debt * ratio, so collateral * 100 == debt * ratio * 100 >= debt * ratio
test prop_fully_collateralized_not_undercollateralized(
  vals via fuzz.both(fuzz.int_between(1, 100), fuzz.int_between(100, 200)),
) fail {
  let (debt, ratio) = vals
  // collateral is exactly debt * ratio, so collateral * 100 = debt * ratio * 100
  // which is >= debt * ratio for any positive ratio — position is healthy
  expect is_undercollateralized(debt * ratio, debt, ratio)
}

// liquidator_pays_discounted must reject when outputs list is empty
// because paid=0 and required>0 for any positive debt and bonus_percent < 100
test prop_no_outputs_fails_liquidator_pays(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(0, 99)),
) fail {
  let (debt, bonus) = vals
  // We need a dummy owner_addr Output; build the minimal one using a known
  // address.  Because outputs is [], paid will always be 0 and required >= 1.
  // We reuse a placeholder by passing an impossible check via empty list.
  expect liquidator_pays_discounted([], Output { address: cardano/address.from_verification_key(#""), value: cardano/assets.zero, datum: cardano/transaction.NoDatum, reference_script: None }, debt, bonus)
}

// is_undercollateralized must return False when collateral is very large
// relative to debt (overcollateralized)
test prop_overcollateralized_not_undercollateralized(
  debt via fuzz.int_between(1, 100),
) fail {
  // collateral is 10x debt, ratio=150: collateral*100 = debt*1000 >> debt*150
  expect is_undercollateralized(debt * 10, debt, 150)
}

use aiken/collection/list
use aiken/fuzz
use cardano/assets.{lovelace_of}
use cardano/transaction.{Output, OutputReference, Transaction}
pub type CdpDatum {
  owner:             ByteArray,
  collateral:        Int,
  debt:              Int,
  liquidation_ratio: Int,
  min_collateral:    Int,
}

pub type CdpRedeemer {
  Repay
  Liquidate
}

fn is_undercollateralized(collateral: Int, debt: Int, ratio: Int) -> Bool {
  debt > 0 && collateral * 100 < debt * ratio
}

/// Position must have at least min_collateral to be liquidatable (dust guard)
fn is_liquidatable(
  collateral:     Int,
  debt:           Int,
  ratio:          Int,
  min_collateral: Int,
) -> Bool {
  collateral >= min_collateral && is_undercollateralized(collateral, debt, ratio)
}

fn liquidator_pays_debt(
  outputs:       List<Output>,
  owner_addr:    Output,
  debt_lovelace: Int,
) -> Bool {
  let paid =
    list.foldl(
      outputs,
      0,
      fn(o, acc) {
        if o.address == owner_addr.address {
          acc + lovelace_of(o.value)
        } else {
          acc
        }
      },
    )
  paid >= debt_lovelace
}

validator cdp_dust_guard {
  spend(
    datum: Option<CdpDatum>,
    redeemer: CdpRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Repay -> list.has(self.extra_signatories, d.owner)
      Liquidate ->
        is_liquidatable(
          d.collateral,
          d.debt,
          d.liquidation_ratio,
          d.min_collateral,
        )
    }
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_dust_guard_undercollateralized_above_min(debt via fuzz.int_at_least(1)) {
  let collateral = debt * 119
  is_liquidatable(collateral, debt * 100, 120, 1)
}

test prop_dust_guard_below_min_not_liquidatable(debt via fuzz.int_at_least(1)) {
  let collateral = debt * 119
  !is_liquidatable(collateral, debt * 100, 120, collateral + 1)
}

test prop_dust_guard_overcollateralized_not_liquidatable(debt via fuzz.int_at_least(1)) {
  !is_liquidatable(debt * 150, debt * 100, 120, 1)
}

test prop_undercollateralized_inverse(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_at_least(1)),
) {
  let (collateral, debt) = vals
  let ratio = 150
  !(is_undercollateralized(collateral, debt, ratio) && collateral * 100 >= debt * ratio)
}

// ── Negative / fail tests ────────────────────────────────────────────────────

// A position with zero debt can never be undercollateralized
test prop_zero_debt_not_undercollateralized(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_between(100, 300)),
) fail {
  let (collateral, ratio) = vals
  expect is_undercollateralized(collateral, 0, ratio)
}

// A well-collateralized position (collateral*100 >= debt*ratio) must NOT be
// flagged as undercollateralized — verifying the inverse always fails.
test prop_overcollateralized_not_undercollateralized(
  debt via fuzz.int_between(1, 100),
) fail {
  // collateral = debt * ratio, so collateral*100 == debt*100*ratio/1
  // with ratio=150: collateral*100 = debt*150*100 >= debt*150 → always healthy
  let collateral = debt * 150
  let ratio = 150
  expect is_undercollateralized(collateral, debt, ratio)
}

// A position below min_collateral dust guard must NOT be liquidatable,
// even when it is genuinely undercollateralized.
test prop_below_min_collateral_never_liquidatable(
  debt via fuzz.int_between(1, 1000),
) fail {
  // collateral is undercollateralized: collateral*100 < debt*150
  // but min_collateral is set higher than collateral, blocking liquidation
  let collateral = debt
  let min_collateral = collateral + 1
  expect is_liquidatable(collateral, debt, 150, min_collateral)
}

// liquidator_pays_debt with an empty output list always pays 0,
// which is always less than any positive debt requirement.
test prop_no_outputs_never_pays_debt(
  debt_lovelace via fuzz.int_at_least(1),
) fail {
  // dummy owner_addr — address is never matched because outputs is empty
  let dummy_output =
    Output {
      address: cardano/address.from_verification_key(#"deadbeef"),
      value: assets.zero,
      datum: transaction.NoDatum,
      reference_script: None,
    }
  expect liquidator_pays_debt([], dummy_output, debt_lovelace)
}

use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use aiken/fuzz
use cardano/address
use cardano/assets.{PolicyId, quantity_of}
use cardano/fuzz as cfuzz
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}
pub type State {
  Idle
  Active
  Locked
  Closing
}

pub type StateRedeemer {
  Advance
  Reset
  Terminate
}

pub type MachineDatum {
  state:        State,
  admin:        VerificationKeyHash,
  beacon_policy: PolicyId,
  beacon_name:  ByteArray,
}

/// Valid transitions: Idle→Active, Active→Locked, Locked→Closing
fn valid_transition(from: State, to: State, redeemer: StateRedeemer) -> Bool {
  when redeemer is {
    Advance ->
      when from is {
        Idle    -> to == Active
        Active  -> to == Locked
        Locked  -> to == Closing
        Closing -> False
      }
    Reset     -> to == Idle
    Terminate -> to == Closing
  }
}

/// The beacon NFT must be present in the continuing output
fn beacon_preserved(
  outputs:      List<Output>,
  own_addr:     address.Address,
  beacon_policy: PolicyId,
  beacon_name:  ByteArray,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      o.address == own_addr
        && quantity_of(o.value, beacon_policy, beacon_name) == 1
    },
  )
}

fn state_from_output(output: Output) -> Option<MachineDatum> {
  when output.datum is {
    InlineDatum(raw) -> {
      expect d: MachineDatum = raw
      Some(d)
    }
    _ -> None
  }
}

validator beacon_state_machine {
  spend(
    datum: Option<MachineDatum>,
    redeemer: StateRedeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    // Find own input to get address
    expect Some(own_input) =
      list.find(self.inputs, fn(i) { i.output_reference == own_ref })
    let own_addr = own_input.output.address
    // Find continuing output with new datum
    expect Some(next_output) =
      list.find(self.outputs, fn(o) { o.address == own_addr })
    expect Some(next_d) = state_from_output(next_output)
    // Validate
    valid_transition(d.state, next_d.state, redeemer)
      && beacon_preserved(self.outputs, own_addr, d.beacon_policy, d.beacon_name)
      && (
        when redeemer is {
          Advance -> True
          Reset   -> list.has(self.extra_signatories, d.admin)
          Terminate -> list.has(self.extra_signatories, d.admin)
        }
      )
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_valid_transition_advance_idle() {
  valid_transition(Idle, Active, Advance)
}

test prop_valid_transition_advance_active() {
  valid_transition(Active, Locked, Advance)
}

test prop_valid_transition_advance_locked() {
  valid_transition(Locked, Closing, Advance)
}

test prop_valid_transition_closing_advance_fails() {
  !valid_transition(Closing, Idle, Advance)
}

test prop_valid_transition_reset_always_to_idle() {
  valid_transition(Active, Idle, Reset)
    && valid_transition(Locked, Idle, Reset)
    && valid_transition(Closing, Idle, Reset)
}

test prop_valid_transition_wrong_target_fails() {
  !valid_transition(Idle, Locked, Advance)
}

// ── Negative / fail tests ────────────────────────────────────────────────────

/// Advancing from Closing is always invalid regardless of target state.
test prop_closing_advance_always_rejected() fail {
  expect valid_transition(Closing, Closing, Advance)
}

/// Advancing from Idle to any state other than Active must be rejected.
/// We pick Locked and Closing as concrete wrong targets.
test prop_idle_advance_wrong_target_locked_rejected() fail {
  expect valid_transition(Idle, Locked, Advance)
}

/// Reset must produce Idle; any non-Idle target is invalid.
/// Active→Closing with Reset must be rejected.
test prop_reset_non_idle_target_rejected() fail {
  expect valid_transition(Active, Closing, Reset)
}

/// beacon_preserved returns False when the outputs list is empty,
/// regardless of the policy/name being searched for.
test prop_beacon_preserved_empty_outputs_rejected(
  policy via cfuzz.policy_id(),
  name via cfuzz.asset_name(),
  addr via cfuzz.address(),
) fail {
  expect beacon_preserved([], addr, policy, name)
}

use aiken/collection/dict
use aiken/collection/list
use aiken/fuzz
use cardano/assets.{PolicyId, lovelace_of}
use cardano/transaction.{Output, OutputReference, Transaction}
pub type StableDatum {
  collateral_lovelace: Int,
  stability_fee:       Int,
}

/// Maximum stablecoins mintable given collateral and stability_fee (as %)
/// e.g. stability_fee = 150 → max = collateral * 100 / 150
fn max_mintable(collateral: Int, stability_fee: Int) -> Int {
  collateral * 100 / stability_fee
}

/// Total minted quantity for a policy (sum of positive values only)
fn total_minted(tokens: dict.Dict<ByteArray, Int>) -> Int {
  list.foldl(
    dict.values(tokens),
    0,
    fn(qty, acc) {
      if qty > 0 {
        acc + qty
      } else {
        acc
      }
    },
  )
}

/// Mint is valid when: amount > 0 and amount ≤ max_mintable(collateral, fee)
fn mint_within_collateral(
  mint_amount: Int,
  collateral:  Int,
  stability_fee: Int,
) -> Bool {
  mint_amount > 0 && mint_amount <= max_mintable(collateral, stability_fee)
}

/// Collateral output to the script must carry enough lovelace
fn collateral_sufficient(
  outputs:   List<Output>,
  own_addr:  Output,
  required:  Int,
) -> Bool {
  let deposited =
    list.foldl(
      outputs,
      0,
      fn(o, acc) {
        if o.address == own_addr.address {
          acc + lovelace_of(o.value)
        } else {
          acc
        }
      },
    )
  deposited >= required
}

validator stablecoin_mint_gate {
  mint(
    _redeemer: Data,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let minted = total_minted(tokens)
    minted > 0
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_max_mintable_at_100_pct(collateral via fuzz.int_at_least(1)) {
  max_mintable(collateral, 100) == collateral
}

test prop_max_mintable_decreases_with_fee(
  vals via fuzz.both(fuzz.int_at_least(1000), fuzz.int_between(101, 200)),
) {
  let (collateral, fee) = vals
  max_mintable(collateral, fee) < max_mintable(collateral, 100)
}

test prop_mint_within_collateral_ok(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_between(100, 200)),
) {
  let (collateral, fee) = vals
  let max = max_mintable(collateral, fee)
  if max > 0 {
    mint_within_collateral(max, collateral, fee)
  } else {
    True
  }
}

test prop_mint_above_collateral_fails(
  vals via fuzz.both(fuzz.int_at_least(100), fuzz.int_between(100, 200)),
) {
  let (collateral, fee) = vals
  let max = max_mintable(collateral, fee)
  !mint_within_collateral(max + 1, collateral, fee)
}

// ── Negative / fail tests ────────────────────────────────────────────────────

/// Zero mint amount is always rejected regardless of collateral
test prop_zero_mint_rejected(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_between(100, 300)),
) fail {
  let (collateral, fee) = vals
  expect mint_within_collateral(0, collateral, fee)
}

/// Negative mint amount is always rejected
test prop_negative_mint_rejected(
  vals via fuzz.both(fuzz.int_between(-10000, -1), fuzz.int_between(100, 300)),
) fail {
  let (mint_amount, fee) = vals
  expect mint_within_collateral(mint_amount, 1000, fee)
}

/// Minting more than max_mintable is always rejected:
/// With collateral=100 and fee=200, max=50; any mint_amount >= 51 fails.
test prop_overcollateral_mint_rejected(
  mint_amount via fuzz.int_between(51, 10000),
) fail {
  // collateral=100, fee=200 → max_mintable = 100*100/200 = 50
  expect mint_within_collateral(mint_amount, 100, 200)
}

/// No outputs to the script address means deposited lovelace is 0,
/// so any required > 0 causes collateral_sufficient to return False.
test prop_no_outputs_collateral_insufficient(
  required via fuzz.int_at_least(1),
) fail {
  // Empty output list — deposited = 0, required >= 1 → False
  expect collateral_sufficient([], Output { address: ..., value: assets.zero, datum: NoDatum, reference_script: None }, required)
}
